import React, { useState, useMemo, useRef, useCallback } from 'react';
import { generateSpeech, decodeAudioData, audioBufferToWav } from '../services/geminiService';

interface Voice { id: string; name: string; apiId: string; description?: string; }

const generateVietnameseVoices = () => {
  const femaleNames = ['Mai', 'Lan', 'Cúc', 'Trúc', 'Hương', 'Thảo', 'Trang', 'Huyền', 'Linh', 'Ngọc', 'Tuyết', 'Hạnh', 'Vân', 'Nhung', 'Phượng', 'Thúy', 'Diễm', 'Kiều', 'Bích', 'Quỳnh', 'Thu', 'Hằng', 'Nga', 'Yến', 'Oanh', 'Ly', 'My', 'Vy', 'Hà', 'Phương'];
  const maleNames = ['Hùng', 'Dũng', 'Tuấn', 'Minh', 'Thắng', 'Nam', 'Việt', 'Đức', 'Trung', 'Hiếu', 'Nghĩa', 'Quang', 'Hải', 'Sơn', 'Tùng', 'Lâm', 'Khánh', 'Hoàng', 'Thành', 'Vinh', 'Bảo', 'Long', 'Phúc', 'Tâm', 'Huy', 'Cường', 'Bình', 'An', 'Kiên', 'Đạt'];
  const regions = [
    { 
      code: 'bac', 
      name: 'Miền Bắc', 
      styles: [
        'Tin tức', 'Kể chuyện', 'Thuyết minh', 'Đối thoại', 
        'Review Công nghệ', 'Review Đồ gia dụng', 'Phật giáo (Giảng kinh)', 'Phong thủy (Tư vấn)'
      ] 
    },
    { 
      code: 'trung', 
      name: 'Miền Trung', 
      styles: [
        'Kể chuyện', 'Tâm sự', 'Đọc thơ', 'Review Chân thực', 
        'Phật giáo (Niệm Phật)', 'Phong thủy (Tử vi)'
      ] 
    },
    { 
      code: 'nam', 
      name: 'Miền Nam', 
      styles: [
        'Tin tức', 'Sôi động', 'Bán hàng', 'Vlog', 'Giải trí', 
        'Review Mỹ phẩm', 'Unboxing', 'Phật giáo (Thuyết pháp)', 'Phong thủy (Khai vận)'
      ] 
    }
  ];
  const voices: { female: Voice[], male: Voice[] } = { female: [], male: [] };
  let fCount = 0; let mCount = 0;
  regions.forEach(reg => {
    reg.styles.forEach(style => {
        const fName = femaleNames[fCount % femaleNames.length];
        let fApiId = 'Kore'; 
        // Zephyr has more vocal color for expressive reviews, storytelling and solemn religious topics
        if (style.includes('Kể chuyện') || style.includes('Tâm sự') || style.includes('Thơ') || style.includes('Mỹ phẩm') || style.includes('Ẩm thực') || style.includes('Thời trang') || style.includes('Vlog') || style.includes('Đồ gia dụng') || style.includes('Phật giáo')) { fApiId = 'Zephyr'; }
        voices.female.push({ id: `vi_f_${reg.code}_${fCount}`, name: `${fName} (${reg.name} - ${style})`, apiId: fApiId, description: `Giọng nữ ${reg.name}, phong cách ${style.toLowerCase()}.` });
        fCount++;

        const mName = maleNames[mCount % maleNames.length];
        let mApiId = 'Puck'; 
        // Charon is authoritative and steady, good for News, Religion, and Feng Shui
        if (style.includes('Tin tức') || style.includes('Thuyết minh') || style.includes('Công nghệ') || style.includes('Bất động sản') || style.includes('Sách') || style.includes('Phật giáo') || style.includes('Phong thủy')) { mApiId = 'Charon'; }
        // Fenrir is the strong/energetic voice suitable for reviews
        if (style.includes('Sôi động') || style.includes('Bán hàng') || style.includes('Giải trí') || style.includes('Du lịch') || style.includes('Unboxing')) { mApiId = 'Fenrir'; }
        voices.male.push({ id: `vi_m_${reg.code}_${mCount}`, name: `${mName} (${reg.name} - ${style})`, apiId: mApiId, description: `Giọng nam ${reg.name}, phong cách ${style.toLowerCase()}.` });
        mCount++;
    });
  });
  return voices;
};

const VI_VOICES = generateVietnameseVoices();

const VOICES_BY_LANGUAGE: Record<string, { female: Voice[], male: Voice[] }> = {
  'vi': VI_VOICES,
  'en': {
    female: [
      {id: 'en_us_1', name: 'Kore (US - Balanced)', apiId: 'Kore', description: 'American English, standard balanced tone.'}, 
      {id: 'en_us_2', name: 'Zephyr (US - Soft)', apiId: 'Zephyr', description: 'American English, soft and gentle.'}
    ],
    male: [
      {id: 'en_us_3', name: 'Puck (US - Deep)', apiId: 'Puck', description: 'American English, deep voice.'}, 
      {id: 'en_us_4', name: 'Fenrir (US - Strong)', apiId: 'Fenrir', description: 'American English, strong and energetic.'}, 
      {id: 'en_us_5', name: 'Charon (US - Authoritative)', apiId: 'Charon', description: 'American English, authoritative news style.'}
    ]
  }
};

