const generateVietnameseVoices = () => {
  const femaleNames = ['Mai', 'Lan', 'Cúc', 'Trúc', 'Hương', 'Thảo', 'Trang', 'Huyền', 'Linh', 'Ngọc'];
  const maleNames = ['Hùng', 'Dũng', 'Tuấn', 'Minh', 'Thắng', 'Nam', 'Việt', 'Đức', 'Trung', 'Hiếu'];
  const regions = [
    { code: 'bac', name: 'Miền Bắc', styles: ['Tin tức', 'Review Công nghệ'] },
    { code: 'nam', name: 'Miền Nam', styles: ['Bán hàng', 'Vlog Giải trí'] }
  ];

  const voices: { female: Voice[], male: Voice[] } = { female: [], male: [] };

  regions.forEach(reg => {
    reg.styles.forEach((style, idx) => {
        const fName = femaleNames[idx % femaleNames.length];
        voices.female.push({ 
            id: `vi_f_${reg.code}_${idx}`, 
            name: `${fName} (${reg.name} - ${style})`, 
            apiId: style.includes('Tin tức') ? 'Kore' : 'Zephyr', 
            description: `Giọng nữ ${reg.name}, phong cách ${style.toLowerCase()}.`,
            gender: 'NU'
        });

        const mName = maleNames[idx % maleNames.length];
        voices.male.push({ 
            id: `vi_m_${reg.code}_${idx}`, 
            name: `${mName} (${reg.name} - ${style})`, 
            apiId: style.includes('Tin tức') ? 'Charon' : 'Puck', 
            description: `Giọng nam ${reg.name}, phong cách ${style.toLowerCase()}.`,
            gender: 'NAM'
        });
    });
  });
  return voices;
};

