  const resizeImageToAspectRatio = (base64Str: string, ratioId: string): Promise<string> => {
    return new Promise((resolve) => {
      const img = new Image();
      img.src = base64Str;
      img.onload = () => {
        const canvas = document.createElement('canvas');

        let targetRatio = 1;
        if (ratioId === '9:16') targetRatio = 9/16;
        else if (ratioId === '4:5') targetRatio = 4/5;
        else if (ratioId === '16:9') targetRatio = 16/9;

        let canvasW, canvasH;
        const currentRatio = img.width / img.height;

        if (currentRatio > targetRatio) {
            canvasW = img.width;
            canvasH = img.width / targetRatio;
        } else {
            canvasH = img.height;
            canvasW = img.height * targetRatio;
        }

        canvas.width = canvasW;
        canvas.height = canvasH;

        const ctx = canvas.getContext('2d');
        if (ctx) {
            ctx.fillStyle = "#FFFFFF"; 
            ctx.fillRect(0, 0, canvas.width, canvas.height);

            const scaleFactor = 0.85; 
            const scale = Math.min(canvasW / img.width, canvasH / img.height) * scaleFactor;

            const w = img.width * scale;
            const h = img.height * scale;
            const x = (canvasW - w) / 2;
            const y = (canvasH - h) / 2;

            ctx.drawImage(img, x, y, w, h);

            resolve(canvas.toDataURL('image/png'));
        }
      };
    });
