export const generateCompositeImage = async (request: GenerationRequest): Promise<string> => {
  const { personImage, productImage, customBackdrop, outfit, pose, backdrop, expression, aspectRatio, camera } = request;

  let backgroundInstruction = '';
  const parts: any[] = [];

  // Determine Background Logic
  if (backdrop.id === 'custom_bg' && customBackdrop) {
      // Logic for Custom Background
      backgroundInstruction = `5. BACKGROUND & ENVIRONMENT (CRITICAL):
       - INPUT IMAGE 3 IS THE BACKGROUND.
       - You MUST use Image 3 as the scene.
       - COMPOSITE Image 1 (Person) and Image 2 (Product) seamlessly into Image 3 (Background).
       - MATCH the lighting, shadows, and color tone of the person and product to perfectly fit the environment of Image 3.
       - Do NOT generate a new background. Do NOT change the content of Image 3, just use it as the setting.`;
  } else if (backdrop.id === 'original_bg') {
      backgroundInstruction = `5. BACKGROUND & ENVIRONMENT:
       CRITICAL: PRESERVE the original background from Image 1. Do not replace the environment.
       The lighting and shadows on the inserted Product (Image 2) must match the existing lighting of Image 1.`;
  } else {
      // Predefined AI generated background
      backgroundInstruction = `5. BACKGROUND & ENVIRONMENT:
       Replace the original background completely.
       New Setting: ${backdrop.prompt}
       Lighting, shadows, and reflections on the subject and product must realistically match this new setting.`;
  }

  const expressionInstruction = expression.id === 'keep'
    ? 'Maintain the exact facial expression and emotion from Image 1. DO NOT MODIFY THE FACE.'
    : `Modify the facial expression to be: "${expression.prompt}". 
       EXTREMELY IMPORTANT: While changing the expression, you MUST PRESERVE the underlying facial structure and identity of the person in Image 1. The person must be instantly recognizable as the original subject.`;

  const poseInstruction = pose.id === 'context_auto'
    ? `3. POSE & ACTION (NATURAL HOLDING):
       - ACTION: The person (Image 1) must be HOLDING the product (Image 2) in a natural, believable way.
       - GRIP PHYSICS: The fingers must wrap around the product realistically based on its 3D shape.
       - If the product is a tube/bottle, the hand should grasp the body or neck firmly.
       - If it's a jar/box, the hand might support it from underneath or hold the edge.
       - INTERACTION: Ensure realistic contact shadows between fingers and product. NO floating objects.`
    : `3. POSE & ACTION (STYLE: ${pose.label}):
       - Action: ${pose.desc}.
       - GRIP PHYSICS: The hand must firmly grasp the product. Fingers must be visibly interacting with the product surface (occlusion, pressure, shadows).
       - Ensure the grip matches the size and weight of the product.`;

  // Camera Angle Logic
  const cameraInstruction = camera && camera.id !== 'standard'
    ? `6. CAMERA ANGLE & VIEWPOINT (IMPORTANT):
       - STYLE: ${camera.label}.
       - INSTRUCTION: ${camera.prompt || camera.desc}
       ${camera.id === 'pov_hands' ? '- NOTE: For POV, focus on the arms/hands extending into the frame from the camera side. The face might be less visible or not visible depending on the angle.' : ''}`
    : `6. CAMERA ANGLE: Standard professional eye-level shot.`;

  const promptText = `
    ROLE: World-Class Commercial Retoucher & Compositor specialized in Realistic Product Integration.

    INPUTS:
    - Image 1: The Person (Reference for FACE/IDENTITY/BODY).
    - Image 2: The Product (Reference for OBJECT).
    ${(backdrop.id === 'custom_bg' && customBackdrop) ? '- Image 3: The Custom Background (Reference for SCENE).' : ''}

    TASK:
    Create a highly photorealistic commercial composite where the person from Image 1 is ACTUALLY HOLDING the product from Image 2.

    CORE REQUIREMENTS (REALISTIC INTERACTION):
    1. PHYSICAL GRIP & HOLDING (TOP PRIORITY):
       - The hand MUST interact with the product physically. 
       - Fingers must curve around the object's volume realistically.
       - OCCLUSION: Fingers must be in front of the object where they grip it. The object should obscure the palm where appropriate.
       - CONTACT SHADOWS: Darken the area where the skin touches the product to show contact and pressure.
       - The grasp must look secure and natural, strictly avoiding "floating product" artifacts.

    2. REALISTIC SCALE & PROPORTION:
       - The product size MUST be realistic relative to the person's hand and face. 
       - ANALYZE Image 2 to guess dimensions. (e.g., A serum bottle is small, a shampoo bottle is medium).
       - Do NOT make the product giant. It must fit comfortably in the hand.

    3. IDENTITY & PRODUCT FIDELITY:
       - PRESERVE the Person's Face and Identity (Image 1).
       - PRESERVE the Product's Branding, Text, and Details (Image 2).

    4. INTEGRATION:
       - Lighting on the product must match the scene.
       - Reflections on the product must match the environment.

    ${expressionInstruction}
    2. OUTFIT: ${outfit.id === 'keep' ? 'Keep the original outfit from Image 1.' : `Change the person's outfit to: ${outfit.label} (${outfit.desc}). Fit naturally.`}
    ${poseInstruction}
    ${backgroundInstruction}
    ${cameraInstruction}

    OUTPUT QUALITY: High resolution, commercial photography quality.
  `;

  // Construct the Parts array
  parts.push({ text: promptText });
  parts.push({ 
    inlineData: { 
      mimeType: personImage.mimeType, 
      data: personImage.base64 
    } 
  });
  parts.push({ 
    inlineData: { 
      mimeType: productImage.mimeType, 
      data: productImage.base64 
    } 
  });

  // If custom background exists, add it as the 3rd image part
  if (backdrop.id === 'custom_bg' && customBackdrop) {
      parts.push({
          inlineData: {
              mimeType: customBackdrop.mimeType,
              data: customBackdrop.base64
          }
      });
  }

  try {
    const response = await ai.models.generateContent({
      model: 'gemini-2.5-flash-image',
      contents: {
        parts: parts
      },
      config: {
        responseModalities: ['IMAGE'], // Only want image back
        temperature: 0.2, // Lowered for higher precision
        imageConfig: {
          aspectRatio: aspectRatio.id // "1:1", "3:4", "9:16", "16:9", "4:3"
        }
      }
    });

    // Check for inline data (image) in the response parts
    const partsRes = response.candidates?.[0]?.content?.parts;

    if (partsRes) {
        for (const part of partsRes) {
            if (part.inlineData && part.inlineData.data) {
                return `data:image/png;base64,${part.inlineData.data}`;
            }
        }
    }

    throw new Error("No image generated in the response.");

  } catch (error) {
    console.error("Gemini API Error:", error);
    throw error;
  }
};

