                  <div>
                    <label className="block text-xs font-bold font-display text-slate-400 uppercase tracking-widest mb-2">Tải ảnh sản phẩm gốc</label>
                    <div onClick={() => fileInputRef.current?.click()} className={`relative w-full aspect-square rounded-[1.5rem] border-2 border-dashed transition-all cursor-pointer flex flex-col items-center justify-center overflow-hidden group ${uploadedImage ? 'border-orange-500 bg-orange-50' : 'border-slate-200 bg-slate-50 hover:bg-slate-100'}`}>
                      {uploadedImage ? (
                        <>
                          <img src={uploadedImage} alt="Upload" className="w-full h-full object-contain p-4" />
                          <div className="absolute inset-0 bg-black/40 flex items-center justify-center opacity-0 group-hover:opacity-100 transition-all backdrop-blur-sm">
                            <p className="text-white font-bold text-sm flex items-center gap-2 bg-black/20 p-2 rounded-xl"><RefreshCw size={18}/> Đổi ảnh</p>
                          </div>
                        </>
                      ) : (
                        <div className="text-center p-6">
                          <Upload size={32} className="text-slate-300 mx-auto mb-2 group-hover:scale-110 transition-transform" />
                          <p className="text-xs font-bold text-slate-500">Nhấn để tải lên</p>
                        </div>
                      )}
                      <input type="file" ref={fileInputRef} className="hidden" accept="image/*" onChange={handleImageUpload} />
                    </div>
                  </div>
                )}

                {/* Lighting Selection */}
                <div>
                  <label className="block text-xs font-bold font-display text-slate-400 uppercase tracking-widest mb-3">Ánh sáng (Lighting)</label>
                  <div className="grid grid-cols-2 gap-2">
                    {lightingList.map((l) => (
                      <button 
                        key={l.id} 
                        onClick={() => setLighting(l.id)} 
                        className={`p-3 rounded-2xl border text-left flex flex-col gap-1 transition-all ${lighting === l.id ? 'border-orange-500 bg-orange-50 shadow-sm' : 'border-slate-100 bg-slate-50 hover:bg-white'}`}
                      >
                        <div className="flex items-center gap-2">
                          <span className={lighting === l.id ? 'text-orange-600' : 'text-slate-400'}>{l.icon}</span>
                          <span className="text-[10px] font-bold uppercase tracking-tight">{l.name}</span>
                        </div>
                        <span className="text-[8px] text-slate-400 line-clamp-1">{l.desc}</span>
                      </button>
                    ))}
                  </div>
                </div>

                {/* Style Selection */}
                <div>
                  <label className="block text-xs font-bold font-display text-slate-400 uppercase tracking-widest mb-3">Phong cách (Style)</label>
                  <div className="grid grid-cols-1 gap-2 max-h-48 overflow-y-auto custom-scrollbar pr-2">
                    {stylesList.map((s) => (
                      <button 
                        key={s.id} 
                        onClick={() => setStyle(s.id)} 
                        className={`p-3 rounded-2xl border text-left flex items-center gap-3 transition-all ${style === s.id ? 'border-orange-500 bg-orange-50 shadow-sm' : 'border-slate-100 bg-slate-50 hover:bg-white'}`}
                      >
                        <span className="text-lg">{s.icon}</span>
                        <div className="flex flex-col">
                            <span className="text-[10px] font-bold uppercase tracking-tight">{s.name}</span>
                            <span className="text-[9px] text-slate-400">{s.desc}</span>
                        </div>
                      </button>
                    ))}
                  </div>
                </div>

                {/* Other Configs Row */}
                <div className="grid grid-cols-2 gap-4">
                  <div>
                    <label className="block text-xs font-bold font-display text-slate-400 uppercase tracking-widest mb-2">Dịp lễ</label>
                    <select value={occasion} onChange={(e) => setOccasion(e.target.value)} className="w-full p-3 rounded-xl bg-slate-50 border border-slate-100 text-xs font-bold outline-none">
                      {occasions.map(o => <option key={o.id} value={o.id}>{o.icon} {o.name}</option>)}
                    </select>
                  </div>
                  <div>
                    <label className="block text-xs font-bold font-display text-slate-400 uppercase tracking-widest mb-2">Tỉ lệ</label>
                    <select value={aspectRatio} onChange={(e) => setAspectRatio(e.target.value)} className="w-full p-3 rounded-xl bg-slate-50 border border-slate-100 text-xs font-bold outline-none">
                      {aspectRatios.map(r => <option key={r.id} value={r.id}>{r.name}</option>)}
                    </select>
                  </div>
                </div>

                {/* Action Button */}
                <button
                  onClick={activeTab === 'concept' ? generateConcept : generateRemixImage}
                  disabled={loading}
                  className={`w-full py-4 rounded-2xl font-black font-display text-sm text-white shadow-lg transition-all flex items-center justify-center gap-3 active:scale-95 ${loading ? 'bg-slate-300' : 'bg-gradient-to-r from-orange-600 to-amber-600 hover:shadow-orange-200'}`}
                >
                  {loading ? <Loader2 className="animate-spin" size={20} /> : <Sparkles size={20} />}
                  {loading ? 'ĐANG XỬ LÝ...' : (activeTab === 'concept' ? 'TẠO CONCEPT' : 'BIẾN HÌNH NGAY')}
                </button>
                {error && <p className="text-red-500 text-xs text-center font-bold">{error}</p>}
              </div>
            </div>
          </div>

          {/* Results Column */}
          <div className="md:col-span-8">
            {activeTab === 'concept' ? (
                !result ? (
                    <div className="h-full min-h-[500px] flex flex-col items-center justify-center bg-white rounded-[2.5rem] border border-slate-100 shadow-inner">
                        <div className="w-20 h-20 bg-slate-50 rounded-full flex items-center justify-center mb-4 text-slate-200">
                          <Lightbulb size={40} />
                        </div>
                        <p className="text-slate-400 font-display font-bold uppercase tracking-widest text-xs">Concept của bạn sẽ xuất hiện tại đây</p>
                    </div>
                ) : (
                    <div className="bg-white rounded-[2.5rem] shadow-2xl shadow-slate-200/50 overflow-hidden border border-slate-100 animate-in fade-in slide-in-from-bottom-4 duration-500">
                        <div className="bg-slate-900 text-white p-8 relative overflow-hidden">
                            <div className="absolute top-0 right-0 w-64 h-64 bg-orange-600/20 rounded-full blur-3xl"></div>
                            <h2 className="text-3xl font-black font-display relative z-10">{result.conceptName}</h2>
                            <p className="text-slate-400 text-sm mt-2 relative z-10 italic">{result.visualDescription}</p>
                        </div>
                        <div className="p-8 space-y-8">
                            <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
                                <div className="bg-slate-50 p-6 rounded-2xl">
                                    <h4 className="font-bold font-display text-slate-800 mb-2 flex items-center gap-2 text-xs uppercase tracking-widest"><Layers size={14} className="text-orange-500"/> Bối cảnh</h4>
                                    <p className="text-sm text-slate-600 leading-relaxed font-body">{result.background}</p>
                                </div>
                                <div className="bg-slate-50 p-6 rounded-2xl">
                                    <h4 className="font-bold font-display text-slate-800 mb-2 flex items-center gap-2 text-xs uppercase tracking-widest"><Aperture size={14} className="text-orange-500"/> Ánh sáng</h4>
                                    <p className="text-sm text-slate-600 leading-relaxed font-body">{result.lighting}</p>
                                </div>
                            </div>
                            <div className="bg-gradient-to-br from-orange-50 to-amber-50/30 p-6 rounded-[2rem] border border-orange-100">
                                <div className="flex justify-between items-center mb-4">
                                  <h4 className="font-bold font-display text-orange-900 flex items-center gap-2 text-sm uppercase"><MessageSquare size={18} /> Caption TikTok</h4>
                                  <button onClick={() => { copyToClipboard(result.tiktokCaption + "\n" + result.hashtags); setIsCaptionCopied(true); setTimeout(()=>setIsCaptionCopied(false), 2000); }} className="text-[10px] font-bold bg-white text-orange-600 px-3 py-1.5 rounded-full shadow-sm hover:shadow-md transition-all flex items-center gap-1">
                                    {isCaptionCopied ? <Check size={12}/> : <Copy size={12}/>} {isCaptionCopied ? 'Đã chép' : 'Copy'}
                                  </button>
                                </div>
                                <p className="text-slate-800 text-lg font-bold leading-relaxed mb-3 whitespace-pre-line">{result.tiktokCaption}</p>
                                <p className="text-sm text-orange-600 font-bold">{result.hashtags}</p>
                            </div>
                            <div className="border-t border-slate-100 pt-6">
                                <div className="flex justify-between items-center mb-4">
                                    <h4 className="font-bold font-display text-slate-800 flex items-center gap-2 text-xs uppercase"><Sparkles size={16} className="text-purple-500"/> Prompt Hình Ảnh (English)</h4>
                                    <button onClick={() => { copyToClipboard(result.aiPrompt); setIsPromptCopied(true); setTimeout(()=>setIsPromptCopied(false), 2000); }} className="text-xs font-bold text-purple-600 bg-purple-50 px-3 py-1.5 rounded-full hover:bg-purple-100">
                                      {isPromptCopied ? 'Đã copy' : 'Copy Prompt'}
                                    </button>
                                </div>
                                <div className="bg-slate-900 text-purple-200 p-6 rounded-2xl text-xs font-mono leading-relaxed selection:bg-purple-500 selection:text-white">
                                  {result.aiPrompt}
                                </div>
                            </div>
                        </div>
                    </div>
                )
            ) : (
                <div className="h-full min-h-[600px] bg-slate-900 rounded-[3rem] p-6 flex flex-col items-center justify-center relative overflow-hidden shadow-2xl">
                    <div className="absolute inset-0 bg-[radial-gradient(circle_at_center,rgba(249,115,22,0.15)_0%,transparent_70%)] pointer-events-none"></div>

                    {!generatedImage ? (
                        <div className="text-center z-10 max-w-sm px-6">
                            <div className="w-24 h-24 bg-white/5 backdrop-blur-xl rounded-[2rem] flex items-center justify-center mx-auto mb-8 border border-white/10">
                                {loading ? <Loader2 size={40} className="text-orange-500 animate-spin" /> : <ImageIcon size={40} className="text-orange-500" />}
                            </div>
                            <h3 className="text-2xl font-display font-black text-white mb-4">
                                {loading ? 'AI đang xử lý...' : 'Studio Biến Hình'}
                            </h3>
                            <p className="text-slate-400 text-sm leading-relaxed">
                                {loading 
                                    ? 'Đang phân tích cấu trúc sản phẩm và phối hợp ánh sáng chuyên nghiệp. Vui lòng không đóng trình duyệt...' 
                                    : 'Tải ảnh sản phẩm lên, chọn phong cách & ánh sáng ưa thích, AI sẽ tạo ra một bối cảnh hoàn toàn mới.'}
                            </p>
                        </div>
                    ) : (
                        <div className="w-full h-full flex flex-col items-center z-10 animate-in fade-in zoom-in-95 duration-700">
                            <div className="relative w-full flex-1 flex items-center justify-center bg-black/40 rounded-[2rem] border border-white/10 p-6 mb-6 backdrop-blur-md overflow-hidden group">
                                <img src={generatedImage} alt="AI Generated" className="max-w-full max-h-full object-contain rounded-xl shadow-2xl transition-transform duration-500 group-hover:scale-[1.02]" />
                                <div className="absolute top-6 left-6 bg-black/60 backdrop-blur-md px-4 py-2 rounded-xl border border-white/10 flex items-center gap-2 text-white text-[10px] font-black uppercase tracking-widest">
                                    <ShieldCheck size={14} className="text-green-500"/> Product Protected
                                </div>
                                <a href={generatedImage} download="remix.png" className="absolute bottom-6 right-6 p-4 bg-orange-600 text-white rounded-full shadow-lg hover:bg-orange-500 transition-all active:scale-90">
                                  <Download size={24}/>
                                </a>
                            </div>

                            <div className="flex flex-wrap justify-center gap-3 w-full">
                                <button onClick={() => setGeneratedImage(null)} className="px-6 py-3 bg-white/10 text-white rounded-2xl font-bold font-display flex items-center gap-2 hover:bg-white/20 transition-all backdrop-blur-sm border border-white/10 text-sm">
                                    <RefreshCw size={18} /> Làm lại
                                </button>
                                <button onClick={handleGenerateRemixCaption} disabled={generatingCaption} className="px-6 py-3 bg-gradient-to-r from-orange-500 to-pink-500 text-white rounded-2xl font-bold font-display flex items-center gap-2 hover:shadow-lg transition-all text-sm">
                                    {generatingCaption ? <Loader2 size={18} className="animate-spin"/> : <MessageSquare size={18} />} Caption
                                </button>
                                <button onClick={handleGenerateSoraPrompt} disabled={generatingSora} className="px-6 py-3 bg-gradient-to-r from-purple-600 to-indigo-600 text-white rounded-2xl font-bold font-display flex items-center gap-2 hover:shadow-lg transition-all text-sm">
                                    {generatingSora ? <Loader2 size={18} className="animate-spin"/> : <Video size={18} />} Video Prompt
                                </button>
                            </div>

                            {(remixCaption || soraPrompt) && (
                                <div className="w-full mt-6 grid grid-cols-1 md:grid-cols-2 gap-4 animate-in slide-in-from-bottom-4 duration-500">
                                    {remixCaption && (
                                      <div className="bg-white/5 backdrop-blur-xl border border-white/10 rounded-[1.5rem] p-5">
                                        <div className="flex justify-between items-center mb-2">
                                          <span className="text-orange-400 text-[10px] font-black uppercase tracking-widest">AI Caption</span>
                                          <button onClick={() => {copyToClipboard(remixCaption); alert("Copied!");}} className="text-white/40 hover:text-white transition-colors"><Copy size={14}/></button>
                                        </div>
                                        <p className="text-white text-xs font-medium leading-relaxed">{remixCaption}</p>
                                      </div>
                                    )}
                                    {soraPrompt && (
                                      <div className="bg-white/5 backdrop-blur-xl border border-white/10 rounded-[1.5rem] p-5">
                                        <div className="flex justify-between items-center mb-2">
                                          <span className="text-purple-400 text-[10px] font-black uppercase tracking-widest">Video Prompt</span>
                                          <button onClick={() => {copyToClipboard(soraPrompt); alert("Copied!");}} className="text-white/40 hover:text-white transition-colors"><Copy size={14}/></button>
                                        </div>
                                        <p className="text-white text-[10px] font-mono leading-relaxed line-clamp-4">{soraPrompt}</p>
                                      </div>
                                    )}
                                </div>
                            )}
                        </div>
                    )}
                </div>
            )}
          </div>
        </div>
      </div>
    </div>
  );
}

import React, { useState, useRef } from 'react';
import { Camera, Sparkles, Palette, Lightbulb, Copy, Image as ImageIcon, Wand2, Layers, Aperture, Square, Smartphone, Monitor, LayoutTemplate, MessageSquare, Check, Loader2, Upload, RefreshCw, Download, Video, ShieldCheck, Sun, Zap, Moon } from 'lucide-react';
import { GoogleGenAI } from "@google/genai";

export const PhotoConcept: React.FC = () => {
  const [activeTab, setActiveTab] = useState<'concept' | 'remix'>('remix');

  // State chung
  const [productName, setProductName] = useState('');
  const [style, setStyle] = useState('luxury');
  const [lighting, setLighting] = useState('studio');
  const [occasion, setOccasion] = useState('none');
  const [aspectRatio, setAspectRatio] = useState('1:1');
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState('');

  // State cho Tab 1: Concept Text
  const [productColor, setProductColor] = useState('');
  const [suggestingColor, setSuggestingColor] = useState(false);
  const [result, setResult] = useState<any>(null);
  const [isCaptionCopied, setIsCaptionCopied] = useState(false);
  const [isPromptCopied, setIsPromptCopied] = useState(false);

  // State cho Tab 2: Remix Image
  const [uploadedImage, setUploadedImage] = useState<string | null>(null);
  const [generatedImage, setGeneratedImage] = useState<string | null>(null);
  const [remixCaption, setRemixCaption] = useState('');
  const [generatingCaption, setGeneratingCaption] = useState(false);
  const [soraPrompt, setSoraPrompt] = useState('');
  const [generatingSora, setGeneratingSora] = useState(false);
  const fileInputRef = useRef<HTMLInputElement>(null);

  const stylesList = [
    { id: 'luxury', name: 'Luxury', icon: '💎', desc: 'Marble, lụa, vàng.' },
    { id: 'minimalist', name: 'Minimal', icon: '🌿', desc: 'Sạch sẽ, tinh tế.' },
    { id: 'cute', name: 'Cute', icon: '🐰', desc: 'Màu pastel, decor.' },
    { id: 'cyberpunk', name: 'Cyberpunk', icon: '🚀', desc: 'Đèn neon, tương lai.' },
    { id: 'tropical', name: 'Tropical', icon: '🌴', desc: 'Mùa hè, bãi biển.' },
    { id: 'vintage', name: 'Vintage', icon: '🎞️', desc: 'Film grain, hoài cổ.' },
    { id: 'industrial', name: 'Industrial', icon: '🛠️', desc: 'Bê tông, hiện đại.' },
    { id: 'popart', name: 'Pop Art', icon: '🎨', desc: 'Rực rỡ, tương phản.' },
    { id: 'natural', name: 'Natural', icon: '🍃', desc: 'Cây xanh, hữu cơ.' },
  ];

  const lightingList = [
    { id: 'studio', name: 'Studio Soft', icon: <Zap size={14} />, desc: 'Chuyên nghiệp.' },
    { id: 'golden', name: 'Golden Hour', icon: <Sun size={14} />, desc: 'Nắng chiều vàng.' },
    { id: 'neon', name: 'Neon LED', icon: <Zap size={14} className="text-pink-500" />, desc: 'Đèn LED đa màu.' },
    { id: 'dramatic', name: 'Dramatic', icon: <Aperture size={14} />, desc: 'Bóng đổ đậm.' },
    { id: 'ethereal', name: 'Ethereal', icon: <Moon size={14} />, desc: 'Huyền ảo, mờ.' },
    { id: 'natural_sun', name: 'Sunlight', icon: <Sun size={14} className="text-yellow-500" />, desc: 'Trong trẻo.' },
  ];

  const occasions = [
    { id: 'none', name: 'Mặc định', icon: '📷' },
    { id: 'tet', name: 'Tết Việt Nam', icon: '🏮' },
    { id: 'valentine', name: 'Lễ Tình Nhân', icon: '💘' },
    { id: 'mid_autumn', name: 'Trung Thu', icon: '🥮' },
    { id: 'christmas', name: 'Giáng sinh', icon: '🎄' },
    { id: 'auto', name: 'AI Sáng Tạo', icon: '✨' },
  ];

  const aspectRatios = [
    { id: '1:1', name: 'Vuông (1:1)', icon: <Square size={18} />, desc: '1:1' },
    { id: '9:16', name: 'Dọc (9:16)', icon: <Smartphone size={18} />, desc: '9:16' },
    { id: '4:5', name: 'Chân dung (4:5)', icon: <LayoutTemplate size={18} />, desc: '4:5' },
    { id: '16:9', name: 'Ngang (16:9)', icon: <Monitor size={18} />, desc: '16:9' },
  ];

  // --- Logic API Functions ---
  const suggestColorAI = async () => {
    setSuggestingColor(true);
    const selectedStyle = stylesList.find(s => s.id === style) || stylesList[0];
    const selectedOccasion = occasions.find(o => o.id === occasion) || occasions[0];
    const prompt = `Gợi ý ngắn gọn 1 phối màu (màu chủ đạo và màu phụ) phù hợp nhất cho sản phẩm "${productName || 'sản phẩm chung'}" theo phong cách "${selectedStyle.name}" và dịp "${selectedOccasion.name}". Chỉ trả về tên màu hoặc mã màu bằng tiếng Việt.`;
    try {
      const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
      const response = await ai.models.generateContent({ model: 'gemini-2.5-flash', contents: prompt });
      setProductColor(response.text?.trim() || "Be, Trắng");
    } catch (err) { setProductColor("Trắng kem, Be"); } finally { setSuggestingColor(false); }
  };

  const generateConcept = async () => {
    if (!productName) { setError('Vui lòng nhập tên sản phẩm!'); return; }
    setError(''); setLoading(true); setResult(null);
    const selectedStyle = stylesList.find(s => s.id === style) || stylesList[0];
    const selectedLighting = lightingList.find(l => l.id === lighting) || lightingList[0];
    const systemPrompt = `Tạo concept Art Director JSON: { "conceptName", "visualDescription", "background", "props", "lighting", "colorPalette", "aiPrompt", "tiktokCaption", "hashtags" }`;
    const userPrompt = `Sản phẩm: "${productName}", Màu: "${productColor}", Style: "${selectedStyle.name}", Light: "${selectedLighting.name}", Ratio: ${aspectRatio}.`;
    try {
      const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
      const response = await ai.models.generateContent({ model: 'gemini-2.5-flash', contents: userPrompt, config: { systemInstruction: systemPrompt, responseMimeType: "application/json" } });
      setResult(JSON.parse(response.text || "{}"));
    } catch (err) { setError('Lỗi kết nối AI.'); } finally { setLoading(false); }
  };

  const generateRemixImage = async () => {
    if (!uploadedImage) { setError('Vui lòng tải ảnh lên!'); return; }
    setError(''); setLoading(true); setGeneratedImage(null); setRemixCaption(''); setSoraPrompt('');
    const selectedStyle = stylesList.find(s => s.id === style) || stylesList[0];
    const selectedLighting = lightingList.find(l => l.id === lighting) || lightingList[0];
    const selectedOccasion = occasions.find(o => o.id === occasion) || occasions[0];
    const fullPrompt = `Professional background remix. PRODUCT FIDELITY 100%. Keep labels, logo, and text identical. Style: ${selectedStyle.name}. Lighting: ${selectedLighting.name}. Context: ${selectedOccasion.name}. Photorealistic.`;
    try {
      const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
      const response = await ai.models.generateContent({
          model: 'gemini-2.5-flash-image',
          contents: { parts: [ { text: fullPrompt }, { inlineData: { mimeType: 'image/png', data: uploadedImage.split(',')[1] } } ] },
          config: { responseModalities: ['IMAGE'], temperature: 0.1, imageConfig: { aspectRatio: (aspectRatio === '4:5' ? '3:4' : aspectRatio as any) } }
      });
      const parts = response.candidates?.[0]?.content?.parts;
      if (parts) {
          for (const part of parts) { if (part.inlineData && part.inlineData.data) { setGeneratedImage(`data:image/png;base64,${part.inlineData.data}`); return; } }
      }
      throw new Error("No image");
    } catch (err) { setError('Lỗi tạo ảnh.'); } finally { setLoading(false); }
  };

  const handleGenerateRemixCaption = async () => {
    setGeneratingCaption(true);
    try {
        const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
        const response = await ai.models.generateContent({ model: 'gemini-2.5-flash', contents: "Viết 1 caption viral ngắn cho sản phẩm này." });
        setRemixCaption(response.text?.trim() || "Sản phẩm cực chất! 🌿✨ #viral");
    } catch (e) { setRemixCaption("Ảnh đẹp quá! 💖"); } finally { setGeneratingCaption(false); }
  };

  const handleGenerateSoraPrompt = async () => {
    setGeneratingSora(true);
    try {
        const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
        const response = await ai.models.generateContent({ model: 'gemini-2.5-flash', contents: "Viết prompt video ngắn ASMR cho sản phẩm này." });
        setSoraPrompt(response.text?.trim() || "Video slow-motion...");
    } catch (e) { setSoraPrompt("Lỗi tạo prompt."); } finally { setGeneratingSora(false); }
  };

  const handleImageUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) {
      const reader = new FileReader();
      reader.onloadend = () => setUploadedImage(reader.result as string);
      reader.readAsDataURL(file);
    }
  };

  const copyToClipboard = (text: string) => navigator.clipboard.writeText(text);

  return (
    <div className="h-full bg-slate-50 flex flex-col font-body">
      {/* Tab Switcher - Centered Top */}
