import React, { useState, useCallback } from 'react';
import { 
  Sparkles, Download, RefreshCw, AlertCircle, 
  Box, User, Shirt, Hand, Layers, ImageIcon, Smile, Crop, Megaphone, PenTool, Mic, Lightbulb, Camera, BookOpen, Video, Wand2, Bolt, Eye, ScanEye
} from 'lucide-react';

import { BACKDROPS, OUTFITS, POSES, EXPRESSIONS, ASPECT_RATIOS, CAMERA_ANGLES } from './constants';
import { ProcessedImage, OptionItem } from './types';
import { generateCompositeImage } from './services/geminiService';
import { ImageUploader } from './components/ImageUploader';
import { AIImageGenerator } from './components/AIImageGenerator';
import { TextToSpeech } from './components/TextToSpeech';
import { PromptBuilder } from './components/PromptBuilder';
import { VirtualTryOn } from './components/VirtualTryOn';
import { UserGuide } from './components/UserGuide';
import { SoraPromptGen } from './components/SoraPromptGen';
import { HookGenerator } from './components/HookGenerator';
import { VisionScanner } from './components/VisionScanner';

const App: React.FC = () => {
  const [activeTab, setActiveTab] = useState<'studio' | 'ai_image_generator' | 'text_to_speech' | 'prompt_builder' | 'sora_prompt_gen' | 'hook_generator' | 'vision_scanner'>('studio');
  const [studioMode, setStudioMode] = useState<'composite' | 'try_on'>('composite');

  // --- Fashion Studio State ---
  const [personImage, setPersonImage] = useState<ProcessedImage | null>(null);
  const [productImage, setProductImage] = useState<ProcessedImage | null>(null);
  const [customBackdropImage, setCustomBackdropImage] = useState<ProcessedImage | null>(null);
  const [resultImage, setResultImage] = useState<string | null>(null);

  const [selectedOutfit, setSelectedOutfit] = useState<OptionItem>(OUTFITS[0]);
  const [selectedPose, setSelectedPose] = useState<OptionItem>(POSES[0]);
  const [selectedBackdrop, setSelectedBackdrop] = useState<OptionItem>(BACKDROPS[0]);
  const [selectedExpression, setSelectedExpression] = useState<OptionItem>(EXPRESSIONS[0]);
  const [selectedAspectRatio, setSelectedAspectRatio] = useState<OptionItem>(ASPECT_RATIOS[0]);
  const [selectedCamera, setSelectedCamera] = useState<OptionItem>(CAMERA_ANGLES[0]);

  const [isGenerating, setIsGenerating] = useState(false);
  const [error, setError] = useState('');
  const [statusMessage, setStatusMessage] = useState('');

  const processFile = (file: File): Promise<ProcessedImage> => {
    return new Promise((resolve, reject) => {
      const reader = new FileReader();
      reader.readAsDataURL(file);
      reader.onload = (event) => {
        const img = new Image();
        if (event.target?.result) {
            img.src = event.target.result as string;
            img.onload = () => {
              const canvas = document.createElement('canvas');
              const MAX_WIDTH = 1024; 
              const scaleSize = MAX_WIDTH / Math.max(img.width, MAX_WIDTH);
              canvas.width = img.width * scaleSize;
              canvas.height = img.height * scaleSize;
              const ctx = canvas.getContext('2d');
              if (ctx) {
                  ctx.drawImage(img, 0, 0, canvas.width, canvas.height);
                  const dataUrl = canvas.toDataURL(file.type);
                  resolve({
                    preview: dataUrl,
                    base64: dataUrl.split(',')[1],
                    mimeType: file.type
                  });
              } else {
                  reject(new Error("Canvas context failed"));
              }
            };
            img.onerror = (e) => reject(e);
        }
      };
      reader.onerror = error => reject(error);
    });
  };

  const handleFileUpload = async (e: React.ChangeEvent<HTMLInputElement>, type: 'person' | 'product' | 'bg') => {
    const file = e.target.files?.[0];
    if (!file) return;
    try {
      setError('');
      const processed = await processFile(file);
      if (type === 'person') setPersonImage(processed);
      else if (type === 'product') setProductImage(processed);
      else if (type === 'bg') setCustomBackdropImage(processed);
      setResultImage(null);
    } catch (err) {
      setError('Lỗi xử lý ảnh.');
    }
  };

  const handleGenerate = async () => {
    if (!personImage || !productImage) {
      setError('Vui lòng tải lên cả ảnh người mẫu và ảnh sản phẩm.');
      return;
    }
    setIsGenerating(true);
    setError('');
    setResultImage(null);
    setStatusMessage('Đang xử lý...');
    try {
      const result = await generateCompositeImage({
          personImage, productImage,
          customBackdrop: selectedBackdrop.id === 'custom_bg' ? customBackdropImage : null,
          outfit: selectedOutfit, pose: selectedPose, backdrop: selectedBackdrop,
          expression: selectedExpression, aspectRatio: selectedAspectRatio, camera: selectedCamera
      });
      setResultImage(result);
    } catch (err: any) {
      setError(err.message || 'Tạo ảnh thất bại.');
    } finally {
      setIsGenerating(false);
      setStatusMessage('');
    }
  };

  const handleReset = () => {
    setPersonImage(null); setProductImage(null); setCustomBackdropImage(null);
    setResultImage(null); setError('');
  };

  return (
    <div className="flex flex-col lg:h-screen min-h-screen bg-slate-50 font-body">
      {/* Dynamic Header */}
      <header className="flex-none bg-gradient-to-r from-orange-600 to-amber-600 text-white shadow-lg z-30">
        <div className="max-w-[1920px] mx-auto px-4 py-3 flex flex-col md:flex-row items-center justify-between gap-4">
          <div className="flex items-center gap-3 shrink-0">
            <div className="bg-white/20 p-2 rounded-xl backdrop-blur-md">
              <Sparkles className="text-yellow-200 w-5 h-5" />
            </div>
            <h1 className="text-lg md:text-xl font-display font-black tracking-tight uppercase">SỨC MẠNH AI</h1>
          </div>

          <nav className="flex gap-1 overflow-x-auto w-full md:w-auto pb-1 md:pb-0 custom-scrollbar no-scrollbar">
            {[
              { id: 'studio', label: 'Studio', icon: Shirt },
              { id: 'ai_image_generator', label: 'Ảnh AI', icon: Camera },
              { id: 'hook_generator', label: 'Hook & Content', icon: Bolt },
              { id: 'text_to_speech', label: 'Voice', icon: Mic },
              { id: 'prompt_builder', label: 'Prompts', icon: Lightbulb },
              { id: 'sora_prompt_gen', label: 'Sora', icon: Video },
              { id: 'vision_scanner', label: 'Vision', icon: ScanEye }
            ].map(tab => (
              <button 
                key={tab.id}
                onClick={() => setActiveTab(tab.id as any)}
                className={`px-4 py-2 rounded-xl text-xs md:text-sm font-bold flex items-center gap-2 transition-all whitespace-nowrap
                ${activeTab === tab.id ? 'bg-white text-orange-700 shadow-md scale-105' : 'text-white/80 hover:bg-white/10'}`}
              >
                <tab.icon size={16} />
                {tab.label}
              </button>
            ))}
          </nav>
        </div>
      </header>

      {/* Main Responsive Body */}
      <main className="flex-1 min-h-0 relative bg-white lg:overflow-hidden overflow-y-auto">
        <div className="h-full flex flex-col">
          {activeTab === 'studio' && (
            <div className="flex flex-col h-full">
              <div className="flex-none p-3 bg-orange-50/50 border-b border-orange-100 flex justify-center">
                <div className="bg-white p-1 rounded-2xl border border-orange-200 shadow-sm flex gap-1">
                  <button onClick={() => setStudioMode('composite')} className={`px-4 md:px-8 py-2 rounded-xl text-xs md:text-sm font-bold flex items-center gap-2 transition-all ${studioMode === 'composite' ? 'bg-orange-500 text-white shadow-md' : 'text-gray-500 hover:bg-orange-50'}`}><Layers size={14}/> Ghép Ảnh</button>
                  <button onClick={() => setStudioMode('try_on')} className={`px-4 md:px-8 py-2 rounded-xl text-xs md:text-sm font-bold flex items-center gap-2 transition-all ${studioMode === 'try_on' ? 'bg-orange-500 text-white shadow-md' : 'text-gray-500 hover:bg-orange-50'}`}><Wand2 size={14}/> Thử Đồ</button>
                </div>
              </div>
              <div className="flex-1 min-h-0 overflow-hidden">
                {studioMode === 'composite' ? (
                  <div className="h-full grid grid-cols-1 lg:grid-cols-12 overflow-y-auto lg:overflow-hidden lg:divide-x divide-slate-200">
                    <div className="lg:col-span-3 p-4 lg:overflow-y-auto custom-scrollbar bg-slate-50/50 space-y-4">
                      <ImageUploader label="Mặt người mẫu" icon={<User size={14}/>} image={personImage} onUpload={(e)=>handleFileUpload(e,'person')} onRemove={()=>setPersonImage(null)} colorClass="text-orange-600" bgColorClass="bg-orange-50" borderColorClass="border-orange-400" heightClass="h-44 md:h-52"/>
                      <ImageUploader label="Sản phẩm" icon={<Box size={14}/>} image={productImage} onUpload={(e)=>handleFileUpload(e,'product')} onRemove={()=>setProductImage(null)} colorClass="text-amber-600" bgColorClass="bg-amber-50" borderColorClass="border-amber-400" heightClass="h-44 md:h-52"/>
                    </div>
                    <div className="lg:col-span-5 p-4 lg:overflow-y-auto custom-scrollbar bg-white space-y-6">
                      <div className="grid grid-cols-2 gap-4">
                        {[
                          { label: 'Trang phục', icon: Shirt, data: OUTFITS, state: selectedOutfit, set: setSelectedOutfit },
                          { label: 'Dáng tay', icon: Hand, data: POSES, state: selectedPose, set: setSelectedPose },
                          { label: 'Biểu cảm', icon: Smile, data: EXPRESSIONS, state: selectedExpression, set: setSelectedExpression },
