                      </div>
                    </div>
                  </div>
                ) : <VirtualTryOn />}
              </div>
            </div>
          )}
          {activeTab === 'ai_image_generator' && <AIImageGenerator />}
          {activeTab === 'hook_generator' && <HookGenerator />}
