export const PromptBuilder: React.FC = () => {
  const [activeTab, setActiveTab] = useState('prompts');
  const [inputText, setInputText] = useState('');
  const [description, setDescription] = useState('');
  const [selectedStyle, setSelectedStyle] = useState('viral');
  const [isGenerating, setIsGenerating] = useState(false);
  const [generatedPrompts, setGeneratedPrompts] = useState<any[]>([]);

  const handleGenerate = async () => {
      if (!inputText) return;
      setIsGenerating(true);
      try {
          const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
          const prompt = `Tạo 4 prompt Midjourney chi tiết về chủ đề: ${inputText}. Mô tả: ${description}. Style: ${selectedStyle}. Trả về JSON Array: [{id, title, prompt, posting_advice}] bằng Tiếng Việt cho title và advice, Tiếng Anh cho prompt.`;
          const res = await ai.models.generateContent({ model: 'gemini-2.5-flash', contents: prompt });
          const jsonMatch = res.text?.match(/\[.*\]/s);
          setGeneratedPrompts(jsonMatch ? JSON.parse(jsonMatch[0]) : []);
      } catch (e) { console.error(e); }
      finally { setIsGenerating(false); }
  };

  return (
    <div className="lg:h-[calc(100vh-140px)] h-auto flex flex-col lg:flex-row bg-white overflow-hidden rounded-2xl border border-slate-200">
      <div className="lg:w-64 w-full flex-none border-r bg-slate-50/50 p-2 space-y-1">
          <h2 className="p-3 text-sm font-black uppercase text-slate-400 tracking-widest">Danh mục</h2>
          {TABS.map(t => <button key={t.id} onClick={()=>setActiveTab(t.id)} className={`w-full flex items-center gap-3 px-4 py-3 rounded-xl text-sm font-bold transition-all ${activeTab===t.id?`bg-white shadow-sm ${t.colorClass}`:'text-slate-500 hover:bg-slate-100'}`}><t.icon size={18}/>{t.label}</button>)}
      </div>

      <div className="flex-1 p-6 lg:overflow-y-auto custom-scrollbar space-y-6">
            <div className="bg-white p-6 rounded-2xl border shadow-sm">
                <h3 className="font-black text-slate-800 uppercase text-xs mb-4 flex items-center gap-2"><Sparkles className="text-orange-500" size={16}/> Tùy chỉnh tham số</h3>
                <div className="space-y-4">
                    <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                        <div className="space-y-2">
                            <label className="text-[10px] font-black uppercase text-slate-400">Chủ đề chính</label>
                            <input value={inputText} onChange={e=>setInputText(e.target.value)} placeholder="Nhập chủ đề (vd: Mỹ phẩm, Công nghệ)..." className="w-full p-3 bg-slate-50 border rounded-xl outline-none text-sm font-bold" />
                        </div>
                        <div className="space-y-2">
                            <label className="text-[10px] font-black uppercase text-slate-400">Phong cách</label>
                            <select value={selectedStyle} onChange={e=>setSelectedStyle(e.target.value)} className="w-full p-3 bg-slate-50 border rounded-xl outline-none text-sm font-bold">
                                {STYLES.map(s=><option key={s.id} value={s.id}>{s.name}</option>)}
                            </select>
                        </div>
                    </div>
                    <div className="space-y-2">
                        <label className="text-[10px] font-black uppercase text-slate-400">Mô tả bổ sung</label>
                        <textarea value={description} onChange={e=>setDescription(e.target.value)} placeholder="Mô tả chi tiết ý tưởng của bạn..." className="w-full p-3 bg-slate-50 border rounded-xl h-24 text-sm" />
                    </div>
                    <button onClick={handleGenerate} disabled={isGenerating} className="w-full py-4 bg-orange-600 text-white font-black rounded-2xl shadow-lg hover:bg-orange-500 transition-transform active:scale-95 flex items-center justify-center gap-2 uppercase tracking-widest text-xs">
                        {isGenerating ? <RefreshCw className="animate-spin" size={18}/> : <Wand2 size={18}/>} 
                        {isGenerating ? 'Đang soạn thảo...' : 'Tạo Bộ Prompt Ngay'}
                    </button>
                </div>
            </div>

            {generatedPrompts.length > 0 && (
                <div className="grid grid-cols-1 md:grid-cols-2 gap-4 animate-in fade-in slide-in-from-bottom-4">
                    {generatedPrompts.map(p => (
                        <div key={p.id} className="bg-slate-50 border rounded-2xl p-5 space-y-3 relative group">
                            <div className="flex justify-between items-start">
                                <span className="text-[10px] font-black text-orange-600 bg-orange-100 px-2 py-1 rounded">#{p.id}</span>
                                <button onClick={()=>{navigator.clipboard.writeText(p.prompt); alert("Đã copy!")}} className="text-slate-400 hover:text-orange-500"><Copy size={16}/></button>
                            </div>
                            <h4 className="font-bold text-sm text-slate-800">{p.title}</h4>
                            <div className="bg-white p-3 rounded-xl border text-[10px] font-mono text-slate-500 leading-relaxed">{p.prompt}</div>
                            <p className="text-[10px] text-slate-400 italic">💡 {p.posting_advice}</p>
                        </div>
                    ))}
                </div>
            )}
      </div>
    </div>
  );
};

