import React, { useState, useRef } from 'react';
import { GoogleGenAI } from "@google/genai";
import { marked } from 'marked';
import { Upload, Image as ImageIcon, X, FileText, Table, Wand2, Languages, Loader2, Copy, Check, ScanEye, FileCode } from 'lucide-react';

export const VisionScanner: React.FC = () => {
  const [image, setImage] = useState<{base64: string, mimeType: string} | null>(null);
  const [previewUrl, setPreviewUrl] = useState<string | null>(null);
  const [prompt, setPrompt] = useState("Trích xuất toàn bộ văn bản trong hình ảnh này.");
  const [result, setResult] = useState<string>("");
  const [loading, setLoading] = useState(false);
  const [isCopied, setIsCopied] = useState(false);
  const fileInputRef = useRef<HTMLInputElement>(null);

  const handleFileChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) {
      const reader = new FileReader();
      reader.onloadend = () => {
        const res = reader.result as string;
        setPreviewUrl(res);
        setImage({ base64: res.split(',')[1], mimeType: file.type });
      };
      reader.readAsDataURL(file);
    }
  };

  const analyzeImage = async () => {
    if (!image) return;
    setLoading(true); setResult("");
    try {
      const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
      const response = await ai.models.generateContent({
        model: 'gemini-2.5-flash',
        contents: { parts: [ { text: prompt }, { inlineData: { mimeType: image.mimeType, data: image.base64 } } ] }
      });
      setResult(response.text || "Không có nội dung.");
    } catch (err) { alert("Lỗi quét hình ảnh."); }
    finally { setLoading(false); }
  };

  return (
    <div className="max-w-6xl mx-auto px-4 h-full overflow-y-auto custom-scrollbar pb-8">
      <div className="grid grid-cols-1 lg:grid-cols-2 gap-8 py-6">
        <div className="space-y-6">
          <div className="bg-white rounded-2xl shadow-sm border p-6">
            <h1 className="text-sm font-black flex items-center gap-2 text-slate-700 uppercase tracking-widest mb-6">
              <ScanEye className="w-5 h-5 text-orange-500" /> AI Vision Scanner
            </h1>
            <div className="space-y-6">
              <div onClick={()=>fileInputRef.current?.click()} className={`border-2 border-dashed rounded-2xl p-8 text-center cursor-pointer transition-all bg-slate-50 relative group ${previewUrl?'border-orange-500':'border-slate-300'}`}>
                <input type="file" ref={fileInputRef} onChange={handleFileChange} accept="image/*" className="hidden" />
                {previewUrl ? <img src={previewUrl} className="max-h-64 mx-auto rounded-lg" /> : <div className="flex flex-col items-center"><ImageIcon className="w-10 h-10 text-slate-300 mb-2"/><p className="text-xs font-bold text-slate-400">NHẤN ĐỂ TẢI ẢNH CẦN QUÉT</p></div>}
              </div>
              <div className="space-y-4">
                <label className="text-[10px] font-black text-slate-400 uppercase">Công cụ nhanh</label>
                <div className="flex flex-wrap gap-2">
                  <button onClick={()=>setPrompt("Trích xuất văn bản Tiếng Việt chuẩn xác.")} className="px-3 py-1.5 bg-slate-100 text-xs font-bold rounded-lg border hover:bg-orange-50">Lấy Text</button>
                  <button onClick={()=>setPrompt("Trích xuất dữ liệu bảng dưới dạng Markdown Table.")} className="px-3 py-1.5 bg-slate-100 text-xs font-bold rounded-lg border hover:bg-orange-50">Xuất Bảng</button>
                  <button onClick={()=>setPrompt("Dịch nội dung trong ảnh sang Tiếng Việt.")} className="px-3 py-1.5 bg-slate-100 text-xs font-bold rounded-lg border hover:bg-orange-50">Dịch Việt</button>
                </div>
                <textarea value={prompt} onChange={e=>setPrompt(e.target.value)} className="w-full p-3 bg-slate-50 border rounded-xl text-sm h-24 outline-none focus:ring-2 focus:ring-orange-100" />
                <button onClick={analyzeImage} disabled={loading || !image} className="w-full py-4 bg-orange-600 text-white font-black rounded-2xl shadow-lg flex items-center justify-center gap-2 uppercase text-xs active:scale-95 transition-transform">{loading ? <Loader2 className="animate-spin" size={20}/> : <ScanEye size={20}/>} BẮT ĐẦU QUÉT AI</button>
              </div>
            </div>
          </div>
        </div>
        <div className="bg-white rounded-2xl border flex flex-col h-full min-h-[500px] overflow-hidden shadow-sm">
            <div className="p-4 border-b bg-slate-50 flex justify-between items-center"><h2 className="text-xs font-black uppercase text-slate-500">Kết quả phân tích</h2><button onClick={()=>{navigator.clipboard.writeText(result); setIsCopied(true); setTimeout(()=>setIsCopied(false), 2000)}} className="text-[10px] font-bold flex items-center gap-1 bg-white px-3 py-1 rounded-lg border shadow-sm">{isCopied ? <Check size={12} className="text-green-500"/> : <Copy size={12}/>} Copy</button></div>
            <div className="flex-1 p-6 bg-slate-50/30 overflow-y-auto custom-scrollbar">{loading ? <div className="h-full flex flex-col items-center justify-center text-slate-400 gap-2"><Loader2 className="animate-spin"/><p className="text-[10px] font-black uppercase animate-pulse">Gemini đang xử lý...</p></div> : result ? <div className="prose prose-sm font-body" dangerouslySetInnerHTML={{ __html: marked.parse(result) as string }} /> : <div className="h-full flex flex-col items-center justify-center opacity-10"><ScanEye size={64}/></div>}</div>
        </div>
      </div>
    </div>
  );
};

