          outfit: selectedOutfit, pose: selectedPose, backdrop: selectedBackdrop,
          expression: selectedExpression, aspectRatio: selectedAspectRatio, camera: selectedCamera
      });
      setResultImage(result);
    } catch (err: any) {
      setError(err.message || 'Tạo ảnh thất bại.');
    } finally {
      setIsGenerating(false);
      setStatusMessage('');
    }
  };

