export const generateCompositeImage = async (request: GenerationRequest): Promise<string> => {
  const { personImage, productImage, customBackdrop, outfit, pose, backdrop, expression, aspectRatio, camera } = request;

  let backgroundInstruction = '';
  const parts: any[] = [];

  if (backdrop.id === 'custom_bg' && customBackdrop) {
      backgroundInstruction = `5. BACKGROUND & ENVIRONMENT:
       - SỬ DỤNG HÌNH ẢNH 3 LÀM BỐI CẢNH DUY NHẤT.
       - Ghép người (Ảnh 1) và Sản phẩm (Ảnh 2) vào bối cảnh này.
       - Khớp ánh sáng và bóng đổ để trông thật nhất.`;
  } else if (backdrop.id === 'original_bg') {
      backgroundInstruction = `5. BACKGROUND & ENVIRONMENT:
       GIỮ NGUYÊN bối cảnh gốc từ Ảnh 1. Chỉ chèn thêm sản phẩm vào tay người mẫu.`;
  } else {
      backgroundInstruction = `5. BACKGROUND & ENVIRONMENT:
       Thay thế nền bằng: ${backdrop.prompt}
       Ánh sáng và bóng đổ phải khớp với môi trường mới.`;
  }

  const expressionInstruction = expression.id === 'keep'
    ? 'Giữ nguyên biểu cảm gương mặt từ Ảnh 1.'
    : `Thay đổi biểu cảm thành: "${expression.prompt}". GIỮ NGUYÊN cấu trúc khuôn mặt và danh tính người mẫu.`;

  const poseInstruction = pose.id === 'context_auto'
    ? `3. POSE & ACTION: Người mẫu (Ảnh 1) cầm sản phẩm (Ảnh 2) một cách tự nhiên. Ngón tay phải ôm sát vật thể, có bóng đổ tiếp xúc thực tế.`
    : `3. POSE & ACTION (STYLE: ${pose.label}): ${pose.desc}. Bàn tay phải nắm chặt sản phẩm thực tế.`;

  const cameraInstruction = camera && camera.id !== 'standard'
    ? `6. CAMERA ANGLE: ${camera.label}. ${camera.prompt || camera.desc}`
    : `6. CAMERA ANGLE: Góc chụp ngang tầm mắt chuyên nghiệp.`;

  const promptText = `
    ROLE: Chuyên gia Retouch và Composite quảng cáo đẳng cấp thế giới.

    YÊU CẦU TỐI THƯỢNG (TUYỆT ĐỐI KHÔNG VI PHẠM):
    1. BẢO TOÀN SẢN PHẨM 100%: Ảnh sản phẩm (Ảnh 2) PHẢI ĐƯỢC GIỮ NGUYÊN VẸN. KHÔNG thay đổi nhãn mác, KHÔNG thay đổi logo, KHÔNG thay đổi màu sắc bao bì, KHÔNG thay đổi hình dáng sản phẩm. Sản phẩm trong ảnh kết quả phải trông GIỐNG HỆT sản phẩm trong Ảnh 2.
    2. BẢO TOÀN DANH TÍNH: Gương mặt người mẫu trong Ảnh 1 phải giữ nguyên đặc điểm nhận dạng.
    3. TƯƠNG TÁC VẬT LÝ: Bàn tay phải cầm sản phẩm thật sự (có sự che khuất của ngón tay lên vật thể), không được để sản phẩm "bay" lơ lửng.

    TASK: Tạo ảnh quảng cáo chuyên nghiệp ghép người mẫu đang cầm sản phẩm.

    ${expressionInstruction}
    2. TRANG PHỤC: ${outfit.id === 'keep' ? 'Giữ nguyên trang phục Ảnh 1.' : `Thay đổi trang phục thành: ${outfit.label}.`}
    ${poseInstruction}
    ${backgroundInstruction}
    ${cameraInstruction}

    Chất lượng: Siêu thực, độ phân giải cao 8k, ánh sáng thương mại.
  `;

  parts.push({ text: promptText });
  parts.push({ inlineData: { mimeType: personImage.mimeType, data: personImage.base64 } });
  parts.push({ inlineData: { mimeType: productImage.mimeType, data: productImage.base64 } });

  if (backdrop.id === 'custom_bg' && customBackdrop) {
      parts.push({ inlineData: { mimeType: customBackdrop.mimeType, data: customBackdrop.base64 } });
  }

  try {
    const response = await ai.models.generateContent({
      model: 'gemini-2.5-flash-image',
      contents: { parts: parts },
      config: {
        responseModalities: ['IMAGE'],
        temperature: 0.1,
        imageConfig: { aspectRatio: aspectRatio.id }
      }
    });
    const partsRes = response.candidates?.[0]?.content?.parts;
    if (partsRes) {
        for (const part of partsRes) {
            if (part.inlineData && part.inlineData.data) return `data:image/png;base64,${part.inlineData.data}`;
        }
    }
    throw new Error("Không tạo được ảnh.");
  } catch (error) { throw error; }
};

