  const [productName, setProductName] = useState('');
  const [marketingFeedback, setMarketingFeedback] = useState('');
  const [marketingResult, setMarketingResult] = useState<string | null>(null);

  const handleFileUpload = async (e: React.ChangeEvent<HTMLInputElement>, setter: React.Dispatch<React.SetStateAction<ProcessedImage | null>>) => {
    const file = e.target.files?.[0];
    if (!file) return;
    try {
      setError(null);
      const reader = new FileReader();
      reader.readAsDataURL(file);
      reader.onload = (event) => {
        const img = new Image();
        img.src = event.target?.result as string;
        img.onload = () => {
          const canvas = document.createElement('canvas');
          canvas.width = img.width; canvas.height = img.height;
          const ctx = canvas.getContext('2d');
          if (ctx) {
            ctx.drawImage(img, 0, 0);
            const dataUrl = canvas.toDataURL(file.type);
            setter({ preview: dataUrl, base64: dataUrl.split(',')[1], mimeType: file.type });
          }
        };
      };
    } catch (err) { setError('Lỗi xử lý ảnh.'); }
  };

  const handleGenerate = async () => {
    if (!productImage) { setError('Vui lòng tải lên ảnh sản phẩm.'); return; }
    setIsLoading(true); setError(null);
    try {
        if (mode === 'poster') {
            setPosterResult(null);
            const styleObj = POSTER_PHOTO_STYLES.find(s => s.id === selectedPhotoStyle);
            const holidayObj = VN_HOLIDAYS.find(h => h.id === selectedHoliday);
            const combinedPrompt = `${adPrompt}. ${holidayObj?.prompt || ''} ${styleObj?.prompt || ''}. Photorealistic quality.`;
            const result = await generateAdImage(productImage, logoImage, combinedPrompt, selectedAspectRatio);
            setPosterResult(result);
        } else {
            if (!productName) throw new Error('Vui lòng nhập tên sản phẩm.');
            setMarketingResult(null);
            const result = await generateMarketingImage(productImage, faceImage, productName, marketingFeedback, selectedAspectRatio);
            setMarketingResult(result);
        }
    } catch (err: any) { setError(`Lỗi AI: ${err.message}`); } finally { setIsLoading(false); }
  };

  const downloadImage = (url: string | null) => {
    if (url) {
      const link = document.createElement('a');
      link.href = url;
      link.download = `poster-ai.png`;
      link.click();
    }
  };

  return (
    <div className="h-full flex flex-col bg-white overflow-hidden">
      <div className="flex-none p-3 bg-orange-50/50 border-b border-orange-100 flex justify-center">
          <div className="bg-white p-1 rounded-2xl border border-orange-200 shadow-sm flex gap-1">
              <button onClick={()=>setMode('poster')} className={`px-5 py-2 rounded-xl text-xs font-bold flex items-center gap-2 transition-all ${mode==='poster'?'bg-orange-500 text-white shadow-md':'text-gray-500 hover:bg-orange-50'}`}><Megaphone size={14}/> Poster Quảng Cáo</button>
              <button onClick={()=>setMode('marketing')} className={`px-5 py-2 rounded-xl text-xs font-bold flex items-center gap-2 transition-all ${mode==='marketing'?'bg-orange-500 text-white shadow-md':'text-gray-500 hover:bg-orange-50'}`}><Camera size={14}/> Ảnh Lifestyle</button>
              <button onClick={()=>setMode('concept')} className={`px-5 py-2 rounded-xl text-xs font-bold flex items-center gap-2 transition-all ${mode==='concept'?'bg-orange-500 text-white shadow-md':'text-gray-500 hover:bg-orange-50'}`}><Lightbulb size={14}/> Gợi Ý Concept</button>
          </div>
      </div>

      {mode === 'concept' ? <PhotoConcept /> : (
        <div className="flex-1 min-h-0 grid grid-cols-1 lg:grid-cols-12 lg:divide-x divide-slate-200 lg:overflow-hidden overflow-y-auto">
          <div className="lg:col-span-3 p-4 bg-slate-50/50 space-y-4 lg:overflow-y-auto custom-scrollbar">
              <div className="flex items-center gap-2 mb-1"><span className="bg-orange-100 text-orange-700 w-6 h-6 rounded-full flex items-center justify-center text-[10px] font-black">1</span><h3 className="font-black text-slate-500 text-[10px] uppercase tracking-widest">Nguồn Dữ Liệu</h3></div>
              <ImageUploader label="Ảnh Sản Phẩm (Bắt buộc)" icon={<Box size={14}/>} image={productImage} onUpload={(e)=>handleFileUpload(e, setProductImage)} onRemove={()=>setProductImage(null)} colorClass="text-orange-600" bgColorClass="bg-orange-50" borderColorClass="border-orange-400" heightClass="h-44 md:h-52"/>
              <div className="bg-green-50 p-3 rounded-xl border border-green-100 flex items-start gap-2">
                <ShieldCheck size={14} className="text-green-600 mt-0.5 shrink-0" />
                <p className="text-[10px] font-bold text-green-700 leading-tight">AI cam kết giữ nguyên 100% chi tiết sản phẩm. Chỉ thay đổi bối cảnh và tự động thêm ánh sáng phù hợp.</p>
              </div>
              {mode==='poster' ? <ImageUploader label="Logo Thương Hiệu" icon={<Upload size={14}/>} image={logoImage} onUpload={(e)=>handleFileUpload(e,setLogoImage)} onRemove={()=>setLogoImage(null)} colorClass="text-amber-600" bgColorClass="bg-amber-50" borderColorClass="border-amber-400" heightClass="h-32"/> : <ImageUploader label="Ảnh Mặt Mẫu" icon={<User size={14}/>} image={faceImage} onUpload={(e)=>handleFileUpload(e,setFaceImage)} onRemove={()=>setFaceImage(null)} colorClass="text-amber-600" bgColorClass="bg-amber-50" borderColorClass="border-amber-400" heightClass="h-44"/>}
          </div>

          <div className="lg:col-span-5 p-4 bg-white space-y-6 lg:overflow-y-auto custom-scrollbar">
              <div className="flex items-center gap-2 mb-4"><span className="bg-orange-100 text-orange-700 w-6 h-6 rounded-full flex items-center justify-center text-[10px] font-black">2</span><h3 className="font-black text-slate-500 text-[10px] uppercase tracking-widest">Cấu Hình Hình Ảnh</h3></div>

              <div className="space-y-4">
                  <div className="grid grid-cols-2 gap-4">
                      <div className="space-y-2">
                        <label className="text-[10px] font-black uppercase text-slate-400">Khung hình</label>
                        <select value={selectedAspectRatio} onChange={(e)=>setSelectedAspectRatio(e.target.value)} className="w-full p-3 rounded-xl border border-slate-200 bg-slate-50 text-xs font-bold">
                            {ASPECT_RATIOS.map(a=><option key={a.id} value={a.id}>{a.label}</option>)}
                        </select>
                      </div>
                      {mode==='poster' && (
                        <div className="space-y-2">
                          <label className="text-[10px] font-black uppercase text-slate-400">Góc chụp Studio</label>
                          <select value={selectedPhotoStyle} onChange={(e)=>setSelectedPhotoStyle(e.target.value)} className="w-full p-3 rounded-xl border border-slate-200 bg-slate-50 text-xs font-bold">
                              {POSTER_PHOTO_STYLES.map(s=><option key={s.id} value={s.id}>{s.name}</option>)}
                          </select>
                        </div>
                      )}
                  </div>

                  {mode === 'poster' ? (
                      <div className="space-y-4">
                          <div className="bg-slate-50 p-4 rounded-2xl border border-slate-100">
                            <label className="text-[10px] font-black uppercase text-orange-500 mb-3 block">Chủ đề ngày lễ tại Việt Nam</label>
                            <div className="grid grid-cols-4 gap-2">
                                {VN_HOLIDAYS.map(h=><button key={h.id} onClick={()=>setSelectedHoliday(h.id)} className={`p-2 rounded-xl border flex flex-col items-center gap-1 transition-all ${selectedHoliday===h.id?'border-orange-500 bg-white text-orange-700 shadow-sm':'border-transparent bg-white/50 text-slate-400'}`}><span className="text-sm">{h.icon}</span><span className="text-[8px] font-black truncate w-full text-center">{h.name.split(' ')[0]}</span></button>)}
