                          </div>
                          <div className="space-y-2">
                            <label className="text-[10px] font-black uppercase text-slate-400">Mô tả bối cảnh thêm</label>
                            <textarea rows={3} className="w-full p-4 border border-slate-200 rounded-2xl text-xs font-bold bg-slate-50 outline-none focus:ring-2 focus:ring-orange-100" placeholder="AI sẽ tự động thêm ánh sáng phù hợp với mô tả này..." value={adPrompt} onChange={(e)=>setAdPrompt(e.target.value)} />
                          </div>
