export const generateCompositeImage = async (request: GenerationRequest): Promise<string> => {
  const { personImage, productImage, customBackdrop, outfit, pose, backdrop, expression, aspectRatio, camera } = request;

  let backgroundInstruction = '';
  const parts: any[] = [];

  if (backdrop.id === 'custom_bg' && customBackdrop) {
      backgroundInstruction = `5. BỐI CẢNH (ENVIRONMENT):
       - SỬ DỤNG HÌNH ÁNH 3 LÀM BỐI CẢNH DUY NHẤT.
       - Tự động thêm ánh sáng môi trường và bóng đổ thực tế từ bối cảnh này lên người và sản phẩm.`;
  } else if (backdrop.id === 'original_bg') {
      backgroundInstruction = `5. BỐI CẢNH (ENVIRONMENT):
       GIỮ NGUYÊN bối cảnh gốc từ Ảnh 1. Chỉ chèn thêm sản phẩm vào tay người mẫu với ánh sáng khớp hoàn toàn.`;
  } else {
      backgroundInstruction = `5. BỐI CẢNH (ENVIRONMENT):
       Thay thế nền bằng: ${backdrop.prompt}
       Ánh sáng và bóng đổ phải tự động được tính toán để khớp với môi trường mới này.`;
  }

  const promptText = `
    ROLE: Chuyên gia Retouch và Composite quảng cáo chuyên nghiệp.

    YÊU CẦU TỐI THƯỢNG (TUYỆT ĐỐI GIỮ NGUYÊN):
    1. BẢO TOÀN SẢN PHẨM 100%: Ảnh sản phẩm (Ảnh 2) PHẢI ĐƯỢC GIỮ NGUYÊN VẸN TỪNG CHI TIẾT. KHÔNG được thay đổi nhãn mác, KHÔNG thay đổi logo, KHÔNG thay đổi màu sắc bao bì, KHÔNG thay đổi hình dáng sản phẩm. Sản phẩm phải trông GIỐNG HỆT ảnh gốc, chỉ được thay đổi ánh sáng bề mặt để khớp bối cảnh.
    2. TỰ ĐỘNG THÊM ÁNH SÁNG: AI tự động phân tích bối cảnh để thêm ánh sáng (lighting), phản chiếu (reflection) và bóng đổ (shadow) lên sản phẩm và người mẫu sao cho chân thực nhất.

    TASK: Ghép người mẫu (Ảnh 1) đang cầm sản phẩm (Ảnh 2).

    ${expression.id === 'keep' ? 'Giữ biểu cảm Ảnh 1.' : `Đổi biểu cảm: "${expression.prompt}".`}
    2. TRANG PHỤC: ${outfit.id === 'keep' ? 'Giữ nguyên trang phục.' : `Mặc bộ: ${outfit.label}.`}
    3. TƯƠNG TÁC: Người mẫu cầm sản phẩm một cách tự nhiên.
    ${backgroundInstruction}
    ${camera && camera.id !== 'standard' ? `6. GÓC MÁY: ${camera.prompt}` : ''}

    Chất lượng: Siêu thực (Photorealistic), 8k resolution.
  `;

  parts.push({ text: promptText });
  parts.push({ inlineData: { mimeType: personImage.mimeType, data: personImage.base64 } });
  parts.push({ inlineData: { mimeType: productImage.mimeType, data: productImage.base64 } });

  if (backdrop.id === 'custom_bg' && customBackdrop) {
      parts.push({ inlineData: { mimeType: customBackdrop.mimeType, data: customBackdrop.base64 } });
  }

  try {
    const response = await ai.models.generateContent({
      model: 'gemini-2.5-flash-image',
      contents: { parts: parts },
      config: {
        responseModalities: ['IMAGE'],
        temperature: 0.1,
        imageConfig: { aspectRatio: aspectRatio.id }
      }
    });
    const partsRes = response.candidates?.[0]?.content?.parts;
    if (partsRes) {
        for (const part of partsRes) {
            if (part.inlineData && part.inlineData.data) return `data:image/png;base64,${part.inlineData.data}`;
        }
    }
    throw new Error("Không tạo được ảnh.");
  } catch (error) { throw error; }
};

export const generateAdImage = async (
    productImage: ProcessedImage, 
    logoImage: ProcessedImage | null, 
    customPrompt: string,
    aspectRatio: string = "1:1",
    backdropPrompt: string = ""
): Promise<string> => {
    const systemPrompt = `Bạn là chuyên gia nhiếp ảnh quảng cáo thương mại chuyên về PRODUCT FIDELITY (Độ chân thực sản phẩm).

    QUY TẮC BẤT DI BẤT DỊCH:
    1. GIỮ NGUYÊN SẢN PHẨM: Tuyệt đối KHÔNG thay đổi bất kỳ pixel nào của sản phẩm trong ảnh nguồn. Nhãn hiệu, logo, chữ viết, hình dáng, màu sắc nắp/vỏ... PHẢI GIỮ NGUYÊN 100%. 
    2. CHỈ THAY NỀN & ÁNH SÁNG: Chỉ thay đổi môi trường xung quanh dựa trên lựa chọn bối cảnh: ${backdropPrompt}. AI phải tự động thêm ánh sáng phù hợp (soft light, rim light, shadow) để sản phẩm trông như được chụp thật trong môi trường đó.
    3. TÍCH HỢP TỰ NHIÊN: Sản phẩm phải được đặt tự nhiên trên bề mặt bối cảnh mới, có bóng đổ thực tế và phản chiếu nhẹ nếu bề mặt là đá/kính.`;

    const parts: any[] = [];
    let baseQuery = `Tạo ảnh quảng cáo siêu thực. Bối cảnh được chọn: ${backdropPrompt}. Mô tả thêm: ${customPrompt}. GIỮ NGUYÊN 100% CHI TIẾT SẢN PHẨM.`;

    parts.push({ inlineData: { mimeType: productImage.mimeType, data: productImage.base64 } });
    if (logoImage) {
        parts.push({ inlineData: { mimeType: logoImage.mimeType, data: logoImage.base64 } });
        baseQuery += ' Chèn logo từ ảnh 2 vào vị trí tinh tế ở góc ảnh.';
    }
    parts.unshift({ text: baseQuery });

    try {
        const response = await ai.models.generateContent({
            model: 'gemini-2.5-flash-image', 
            contents: { parts: parts },
            config: {
                systemInstruction: systemPrompt,
                responseModalities: ['IMAGE'],
                temperature: 0.1,
                imageConfig: { aspectRatio: aspectRatio }
            }
        });
        const resultParts = response.candidates?.[0]?.content?.parts;
        if (resultParts) {
            for (const part of resultParts) {
                if (part.inlineData && part.inlineData.data) return `data:image/png;base64,${part.inlineData.data}`;
            }
        }
        throw new Error("Không nhận được ảnh.");
    } catch (error) { throw error; }
};

export const generateMarketingImage = async (
  productImg: ProcessedImage,
  faceImg: ProcessedImage | null,
  productName: string,
  feedback: string,
  aspectRatio: string = "9:16",
  backdropPrompt: string = ""
): Promise<string> => {
  const parts: any[] = [{ inlineData: { data: productImg.base64, mimeType: productImg.mimeType } }];
  if (faceImg) parts.push({ inlineData: { data: faceImg.base64, mimeType: faceImg.mimeType } });

  let prompt = `Tạo ảnh Marketing chuyên nghiệp cao cấp.

  YÊU CẦU NGHIÊM NGẶT:
  - GIỮ NGUYÊN 100% HÌNH ẢNH SẢN PHẨM '${productName}'. Không vẽ lại, không làm mờ logo, không thay đổi nhãn mác.
  - CHỈ THAY ĐỔI BỐI CẢNH VÀ ÁNH SÁNG: AI tự động phân bổ ánh sáng từ môi trường mới lên bề mặt sản phẩm.
  - BỐI CẢNH CHỌN: ${backdropPrompt}. 
  - Mô tả bổ sung: ${feedback}. 
  - Nếu có người mẫu, họ phải cầm sản phẩm thực tế một cách tự nhiên.
  - Phim trường hoặc bối cảnh đời thực sang trọng, sắc nét 8k.
  `;

  parts.push({ text: prompt });

  try {
    const response = await ai.models.generateContent({
      model: 'gemini-2.5-flash-image',
      contents: { parts },
      config: { temperature: 0.1, imageConfig: { aspectRatio: aspectRatio } }
    });
    if (response.candidates?.[0]?.content?.parts) {
      for (const part of response.candidates[0].content.parts) {
        if (part.inlineData && part.inlineData.data) return `data:${part.inlineData.mimeType || 'image/png'};base64,${part.inlineData.data}`;
      }
    }
    throw new Error("Lỗi tạo ảnh.");
  } catch (error) { throw error; }
};

export const removeBackground = async (image: ProcessedImage): Promise<string> => {
    const promptText = "Remove the background from the product in the image. The product should be sharp and well-defined, and the background should be completely removed (transparent). Output a PNG image.";
    try {
        const response = await ai.models.generateContent({
            model: 'gemini-2.5-flash-image',
            contents: { parts: [ { text: promptText }, { inlineData: { mimeType: image.mimeType, data: image.base64 } } ] },
            config: { responseModalities: ['IMAGE'], temperature: 0.2 }
        });
        const parts = response.candidates?.[0]?.content?.parts;
        if (parts) {
            for (const part of parts) {
                if (part.inlineData && part.inlineData.data) return `data:image/png;base64,${part.inlineData.data}`;
            }
        }
        throw new Error("Không tách được nền.");
    } catch (error) { throw error; }
};

export const generateAdCopy = async (productName: string, productInfo: string, targetAudience: string, formula: string, formulaDesc: string, hookStyle: string, originalPrice: string, discountPrice: string, imageBase64?: { data: string, mimeType: string } | null): Promise<string> => {
