export const generateVirtualTryOn = async (modelImg: ImageAsset, description: string, lighting: string, filter: string, beautyOptions: string[], backdrop: OptionItem, productImg: ImageAsset | null, aspectRatio: string = "3:4"): Promise<string> => {
    let prompt = `Virtual Try-On. Change outfit. GIỮ NGUYÊN GƯƠNG MẶT VÀ DÁNG NGƯỜI. Target: ${description}. Lighting: ${lighting}.`;
    const parts: any[] = [{ text: prompt }, { inlineData: { mimeType: modelImg.mimeType, data: modelImg.base64.split(',')[1] } }];
    if (productImg) parts.push({ inlineData: { mimeType: productImg.mimeType, data: productImg.base64.split(',')[1] } });
    try {
        const response = await ai.models.generateContent({ model: 'gemini-2.5-flash-image', contents: { parts }, config: { responseModalities: ['IMAGE'], temperature: 0.1, imageConfig: { aspectRatio: aspectRatio } } });
        const resParts = response.candidates?.[0]?.content?.parts;
        if (resParts) for (const part of resParts) if (part.inlineData && part.inlineData.data) return `data:image/png;base64,${part.inlineData.data}`;
        throw new Error("Lỗi.");
    } catch (error) { throw error; }
};

