  const generateRemixImage = async () => {
    if (!uploadedImage) { setError('Vui lòng tải ảnh sản phẩm lên!'); return; }
    setError(''); setLoading(true); setGeneratedImage(null); setRemixCaption(''); setSoraPrompt('');

    const selectedStyle = stylesList.find(s => s.id === style) || stylesList[0];
    const selectedOccasion = occasions.find(o => o.id === occasion) || occasions[0];

    const processedImageBase64Full = await resizeImageToAspectRatio(uploadedImage, aspectRatio);
    const base64Data = processedImageBase64Full.split(',')[1];

    let promptStyleContext = "";
    if (selectedStyle.id === 'luxury') {
        promptStyleContext = "Luxury commercial photography: Elegant, expensive feel, sophisticated lighting, premium textures (marble, silk, glass). Deep contrast, high dynamic range.";
    } else if (selectedStyle.id === 'minimalist') {
        promptStyleContext = "Minimalist commercial photography: Clean, bright, airy, soft shadows, plenty of white space, zen and balanced composition.";
    } else if (selectedStyle.id === 'cute') {
        promptStyleContext = "Playful cute photography: Soft pastel colors, warm diffused lighting, adorable aesthetic props, cheerful and lighthearted mood.";
    } else if (selectedStyle.id === 'vintage') {
        promptStyleContext = "Vintage analog photography: Film grain, warm retro tones, classic decor, nostalgic feel, nostalgic 90s aesthetic.";
    } else if (selectedStyle.id === 'futuristic') {
        promptStyleContext = "Futuristic Cyberpunk photography: Neon lighting (cyan and magenta), high-tech environment, sleek reflective surfaces, cinematic night vibe.";
    } else if (selectedStyle.id === 'natural') {
        promptStyleContext = "Natural organic photography: Sunlight through leaves, green foliage background, earth tones, fresh and healthy lifestyle atmosphere.";
    }

    let promptOccasionContext = "";
    if (selectedOccasion.id === 'tet') {
        promptOccasionContext = "Traditional Vietnamese Lunar New Year (Tet) atmosphere: Red envelopes, golden apricot blossoms, red lanterns, festive celebratory background.";
    } else if (selectedOccasion.id === 'christmas') {
        promptOccasionContext = "Christmas winter atmosphere: Warm fireplace, glowing pine trees, soft snow outside, cozy holiday decorations, festive red and green accents.";
    } else if (selectedOccasion.id === 'valentine') {
        promptOccasionContext = "Romantic Valentine's day atmosphere: Soft pink and red palette, roses, heart shapes, candlelight, intimate and loving vibe.";
    } else if (selectedOccasion.id === 'mid_autumn') {
        promptOccasionContext = "Mid-Autumn festival: Lanterns, mooncakes, warm autumn night setting, full moon glow, family reunion vibe.";
    }

    const fullPrompt = `
      ROLE: High-End Product & Fashion Photographer.
      TASK: Scene Remix (Inpainting & Outpainting).

      STRICT MANDATORY REQUIREMENT - HUMAN & PRODUCT PRESERVATION:
      1. IDENTIFY all subjects (Humans/Faces/Products) in the input image.
      2. FACE PRESERVATION: Use 100% of the face from the uploaded image as the absolute reference. Absolutely preserve the natural and authentic face, correct proportions, exact skin texture, and exact skin tone. 
      3. NO STYLIZATION: Do NOT stylize, do NOT over-beautify, and do NOT change any facial features. The person must look 100% identical to the original reference.
      4. PRODUCT PRESERVATION: Preserve the product EXACTLY AS IT IS. Do NOT modify its shape, colors, labels, logos, or text. Sharp and unditorted branding.

      BACKGROUND GENERATION:
      1. IGNORE the current background of the input image.
      2. GENERATE a professional environment around the preserved subjects.
      3. Style: ${promptStyleContext}
      4. Context: ${promptOccasionContext || "Professional commercial advertising scene."}
      5. The new environment must blend realistically with the subjects via physics-based lighting and shadows.

      QUALITY: 8K resolution, hyper-realistic, crystal clear sharpness, professional commercial grade.
    `;

    let apiAspectRatio = aspectRatio;
    if (aspectRatio === '4:5') apiAspectRatio = '3:4'; 

    try {
      const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
      const response = await ai.models.generateContent({
          model: 'gemini-2.5-flash-image',
          contents: {
              parts: [
                  { text: fullPrompt },
                  { inlineData: { mimeType: 'image/png', data: base64Data } }
              ]
          },
          config: {
              responseModalities: ['IMAGE'],
              temperature: 0.1,
              imageConfig: {
                  aspectRatio: apiAspectRatio 
              }
          }
      });

      const parts = response.candidates?.[0]?.content?.parts;
      if (parts) {
          for (const part of parts) {
              if (part.inlineData && part.inlineData.data) {
                  setGeneratedImage(`data:image/png;base64,${part.inlineData.data}`);
                  return;
              }
          }
      }
      throw new Error("AI không trả về hình ảnh.");
    } catch (err) {
      console.error(err);
      setError('Có lỗi xảy ra khi tạo ảnh. Hãy thử lại!');
    } finally {
      setLoading(false);
    }
  };

  const handleGenerateRemixCaption = async () => {
    setGeneratingCaption(true);
    const selectedStyle = stylesList.find(s => s.id === style) || stylesList[0];
    const selectedOccasion = occasions.find(o => o.id === occasion) || occasions[0];

    const prompt = `
